  return (
    <nav className="bg-zinc-900 text-zinc-50 p-4 md:p-6 shadow-lg sticky top-0 z-50">
      <div className="container mx-auto flex justify-between items-center">
        <a href="#home" className="text-2xl font-bold text-zinc-50 hover:text-zinc-200 transition-colors duration-300">
          SynapseFlow
        </a>

        {/* Desktop Navigation */}
        <div className="hidden md:flex items-center space-x-8">
          <ul className="flex space-x-6 lg:space-x-8">
            {navLinks.map((link) => (
              <li key={link.name}>
                <a
                  href={link.href}
                  className="text-zinc-200 hover:text-zinc-50 transition-colors duration-300 relative group"
                >
                  {link.name}
                  <span className="absolute bottom-0 left-0 w-full h-0.5 bg-zinc-500 scale-x-0 group-hover:scale-x-100 transition-transform duration-300 origin-left"></span>
                </a>
              </li>
            ))}
          </ul>
          <div className="flex space-x-4">
            <button className="px-5 py-2 rounded-md border border-zinc-700 text-zinc-200 hover:bg-zinc-800 transition-all duration-300">
              Login
            </button>
            <button className="px-5 py-2 rounded-md bg-zinc-600 text-white hover:bg-zinc-700 transition-all duration-300">
              Sign Up
            </button>
          </div>
        </div>

        {/* Mobile Menu Button */}
        <div className="md:hidden">
          <button onClick={() => setIsOpen(!isOpen)} className="text-zinc-50 hover:text-zinc-200 focus:outline-none focus:ring-2 focus:ring-zinc-500 rounded-md p-2">
            {isOpen ? <X size={28} /> : <Menu size={28} />}
          </button>
        </div>
      </div>

      {/* Mobile Navigation */}
      {isOpen && (
        <div className="md:hidden mt-4 bg-zinc-800 rounded-md shadow-lg py-4 transition-all duration-300 ease-in-out">
          <ul className="flex flex-col space-y-3 px-4">
            {navLinks.map((link) => (
              <li key={link.name}>
                <a
                  href={link.href}
                  onClick={() => setIsOpen(false)}
                  className="block py-2 text-zinc-200 hover:text-zinc-50 hover:bg-zinc-700 rounded-md px-3 transition-colors duration-300"
                >
                  {link.name}
                </a>
              </li>
            ))}
            <li className="pt-2 border-t border-zinc-700 mt-2">
              <button className="block w-full text-left py-2 px-3 rounded-md border border-zinc-700 text-zinc-200 hover:bg-zinc-700 transition-all duration-300">
                Login
              </button>
            </li>
            <li>
              <button className="block w-full text-left py-2 px-3 rounded-md bg-zinc-600 text-white hover:bg-zinc-700 transition-all duration-300">
                Sign Up
              </button>
            </li>
          </ul>
        </div>
      )}
    </nav>
  );
};

export default Navbar;

