import React, { useState } from 'react';
import { Quote, ArrowLeft, ArrowRight } from 'lucide-react';

const testimonials = [
  {
    quote: "SynapseFlow has revolutionized how we manage our projects. The automation features saved us countless hours every week!",
    author: "Jane Doe",
    title: "CEO, TechInnovate",
    avatar: "https://randomuser.me/api/portraits/women/1.jpg",
  },
  {
    quote: "The insights provided by SynapseFlow are invaluable. We can now make data-driven decisions faster and with more confidence.",
    author: "John Smith",
    title: "CTO, DataSolutions",
    avatar: "https://randomuser.me/api/portraits/men/2.jpg",
  },
  {
    quote: "Integration was a breeze, and the support team is top-notch. Truly a game-changer for our small business.",
    author: "Emily White",
    title: "Founder, CreativeSpark",
    avatar: "https://randomuser.me/api/portraits/women/3.jpg",
  },
  {
    quote: "Our team's productivity has soared since implementing SynapseFlow. It's intuitive, powerful, and essential.",
    author: "Michael Brown",
    title: "Operations Manager, GlobalCorp",
    avatar: "https://randomuser.me/api/portraits/men/4.jpg",
  },
];

const TestimonialCarousel = () => {
  const [currentIndex, setCurrentIndex] = useState(0);

  const nextTestimonial = () => {
    setCurrentIndex((prevIndex) => (prevIndex + 1) % testimonials.length);
  };

  const prevTestimonial = () => {
    setCurrentIndex((prevIndex) =>
      (prevIndex - 1 + testimonials.length) % testimonials.length
    );
  };

  return (
    <section id="testimonials" className="py-16 md:py-24 bg-zinc-950 text-zinc-200">
      <div className="container mx-auto px-6 max-w-4xl">
        <h2 className="text-4xl lg:text-5xl font-bold text-center text-zinc-50 mb-12">
          What Our Users Say
        </h2>
        <p className="text-lg text-center text-zinc-300 max-w-3xl mx-auto mb-16">
          Hear directly from the businesses and individuals who have transformed their operations with SynapseFlow.
        </p>

        <div className="relative bg-zinc-900 p-8 md:p-12 rounded-md shadow-xl flex flex-col items-center">
          <Quote size={48} className="text-zinc-600 mb-6" />
          <p className="text-xl md:text-2xl text-center text-zinc-100 italic mb-8 max-w-2xl">
            "{testimonials[currentIndex].quote}"
          </p>
          <div className="flex items-center space-x-4 mb-8">
            <img
              src={testimonials[currentIndex].avatar}
              alt={testimonials[currentIndex].author}
              className="w-16 h-16 rounded-full object-cover border-2 border-zinc-700"
            />
            <div>
              <p className="font-semibold text-zinc-50">{testimonials[currentIndex].author}</p>
              <p className="text-zinc-400 text-sm">{testimonials[currentIndex].title}</p>
            </div>
          </div>

          {/* Navigation Buttons */}
          <div className="absolute top-1/2 -translate-y-1/2 w-full flex justify-between px-4">
            <button
              onClick={prevTestimonial}
              className="p-3 bg-zinc-800 rounded-full text-zinc-300 hover:bg-zinc-700 hover:text-white transition-colors duration-300 shadow-md focus:outline-none focus:ring-2 focus:ring-zinc-500"
              aria-label="Previous testimonial"
            >
              <ArrowLeft size={24} />
            </button>
            <button
              onClick={nextTestimonial}
              className="p-3 bg-zinc-800 rounded-full text-zinc-300 hover:bg-zinc-700 hover:text-white transition-colors duration-300 shadow-md focus:outline-none focus:ring-2 focus:ring-zinc-500"
              aria-label="Next testimonial"
            >
              <ArrowRight size={24} />
            </button>
          </div>

          {/* Dots Indicator */}
          <div className="flex space-x-2 mt-8">
            {testimonials.map((_, index) => (
              <button
                key={index}
                onClick={() => setCurrentIndex(index)}
                className={`w-3 h-3 rounded-full transition-colors duration-300
                  ${index === currentIndex ? 'bg-zinc-500' : 'bg-zinc-700 hover:bg-zinc-600'}`}
                aria-label={`Go to testimonial ${index + 1}`}
              ></button>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
};

export default TestimonialCarousel;

