  const pricingPlans = [
    {
      name: 'Basic',
      monthlyPrice: 29,
      annualPrice: 299, // ~25/month
      features: [
        '5 Automated Workflows',
        'Basic Analytics Dashboard',
        'Email Support',
        '1000 Task Runs/month',
      ],
      isHighlighted: false,
    },
    {
