      monthlyPrice: 79,
      annualPrice: 799, // ~66/month
      features: [
        'Unlimited Workflows',
        'Advanced Analytics & Reporting',
        'Priority Email & Chat Support',
        '10,000 Task Runs/month',
        'Custom Integrations',
      ],
      isHighlighted: true,
    },
    {
      name: 'Enterprise',
      monthlyPrice: 199,
      annualPrice: 1999, // ~166/month
      features: [
        'Everything in Pro',
        'Dedicated Account Manager',
        '24/7 Phone Support',
        'Unlimited Task Runs',
        'On-Premise Deployment Option',
      ],
      isHighlighted: false,
    },
  ];

  return (
    <section id="pricing" className="py-16 md:py-24 bg-zinc-900 text-zinc-200">
      <div className="container mx-auto px-6 max-w-7xl">
        <h2 className="text-4xl lg:text-5xl font-bold text-center text-zinc-50 mb-12">
          Simple, Transparent Pricing
        </h2>
        <p className="text-lg text-center text-zinc-300 max-w-3xl mx-auto mb-16">
          Choose the plan that best fits your needs, whether you're a startup or a large enterprise.
          No hidden fees, just powerful automation.
        </p>

        {/* Pricing Toggle */}
        <div className="flex justify-center mb-12">
          <div className="relative flex items-center bg-zinc-800 rounded-full p-1 shadow-inner">
            <button
              onClick={() => setIsAnnual(false)}
              className={`px-6 py-2 rounded-full text-lg font-medium transition-all duration-300 ${
                !isAnnual ? 'bg-zinc-600 text-white shadow-md' : 'text-zinc-400 hover:text-zinc-200'
              }`}
            >
              Monthly
            </button>
            <button
              onClick={() => setIsAnnual(true)}
              className={`px-6 py-2 rounded-full text-lg font-medium transition-all duration-300 ${
                isAnnual ? 'bg-zinc-600 text-white shadow-md' : 'text-zinc-400 hover:text-zinc-200'
              }`}
            >
              Annually <span className="text-zinc-300 text-sm ml-2 hidden sm:inline">(Save 15%)</span>
            </button>
          </div>
        </div>

        {/* Pricing Cards */}
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8 items-stretch">
          {pricingPlans.map((plan, index) => (
            <div
              key={index}
              className={`bg-zinc-800 p-8 rounded-md flex flex-col shadow-xl transition-all duration-300
                ${plan.isHighlighted ? 'border-2 border-zinc-500 scale-105' : 'border border-zinc-700 hover:border-zinc-600'}`}
            >
              {plan.isHighlighted && (
                <div className="absolute -top-3 right-4 bg-zinc-500 text-white text-xs font-bold px-3 py-1 rounded-full uppercase tracking-wider">
                  Most Popular
                </div>
              )}
              <h3 className="text-3xl font-bold text-zinc-50 mb-4">{plan.name}</h3>
              <p className="text-zinc-400 text-lg mb-6">
                {plan.name === 'Basic' && 'For individuals and small teams'}
                {plan.name === 'Pro' && 'For growing businesses and power users'}
                {plan.name === 'Enterprise' && 'For large organizations with complex needs'}
              </p>
              <div className="flex items-baseline mb-8">
                <span className="text-5xl font-extrabold text-zinc-50">
                  ${isAnnual ? plan.annualPrice : plan.monthlyPrice}
                </span>
                <span className="text-xl text-zinc-400 ml-2">
                  {isAnnual ? '/year' : '/month'}
                </span>
              </div>
              <ul className="space-y-4 flex-grow mb-10">
                {plan.features.map((feature, i) => (
                  <li key={i} className="flex items-center text-zinc-300">
                    <Check size={20} className="text-zinc-500 mr-3 flex-shrink-0" />
                    <span>{feature}</span>
                  </li>
                ))}
              </ul>
              <button
                className={`w-full py-3 rounded-md text-lg font-semibold transition-all duration-300
                  ${plan.isHighlighted
                    ? 'bg-zinc-500 text-white hover:bg-zinc-600 shadow-lg'
                    : 'bg-zinc-700 text-zinc-100 hover:bg-zinc-600'
                  }`}
              >
                Choose {plan.name}
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default PricingSection;

